// Cases data — loads from cases.json generated by scripts/process-cases.cjs
// If no cases.json exists yet, exports empty arrays

import casesData from './cases.json';

export const CASES = casesData || [];

export const CASE_LIST = CASES.map(c => ({
  id: c.id,
  doorChart: c.doorChart,
  chiefComplaint: c.chiefComplaint,
}));
